#include "flame_sensor.h"
#include <Arduino.h>
#define FLAME_A 34
#define FLAME_D 35
static int _raw=0;static bool _flame=false;static unsigned long _l=0;
void flame_setup(){pinMode(FLAME_A,INPUT);pinMode(FLAME_D,INPUT);Serial.println("[flame] OK");}
void flame_loop(){if(millis()-_l<200)return;_l=millis();_raw=analogRead(FLAME_A);_flame=!digitalRead(FLAME_D);}
int flame_get_raw(){return _raw;}
bool flame_detected(){return _flame;}
